generated_oml:
// Sensing Components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the permanent‑magnet synchronous motor, measuring motor current (I_M) to estimate torque."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Quadrature encoder on the motor shaft, providing angular position."
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Quadrature encoder on the gearbox output shaft, providing angular position."
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

// Data Transmitted (via MQTT)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
    base:desc "Time‑stamped current readings of the motor (I_M), streamed via MQTT."
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
    base:desc "Time‑stamped angular position of the motor shaft, streamed via MQTT."
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
    base:desc "Time‑stamped angular position of the gearbox output shaft, streamed via MQTT."
]

// Data
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Live motor current data stream (I_M)."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo ProcessingComponentEnabler, SimulinkEnabler
]

instance MotorPositionData : DTDFVocab:Data [
    base:desc "Live motor shaft position data stream."
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo ProcessingComponentEnabler, SimulinkEnabler
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Live gearbox output shaft position data stream."
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo ProcessingComponentEnabler, SimulinkEnabler
]

// Models
instance MotorSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the permanent‑magnet synchronous motor (PMSynMotor)."
    DTDFVocab:inputTo SimulinkEnabler
]

instance GearwheelSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel within the series gearbox."
    DTDFVocab:inputTo SimulinkEnabler
]

instance GearboxSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the series gearbox."
    DTDFVocab:inputTo SimulinkEnabler
]

instance FrictionSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model encapsulating friction families (Coulomb‑Viscous, Stribeck, Dahl, LuGre)."
    DTDFVocab:inputTo SimulinkEnabler
]

instance EngineeringSysMLModel : DTDFVocab:Model [
    base:desc "SysML (ISO 27001‑derived) engineering block diagram of the first axis."
    DTDFVocab:inputTo SysMLEnabler
]

instance DataTraceCalculatorModel : DTDFVocab:Model [
    base:desc "Calculation model for deriving torque from current, velocity, and acceleration."
    DTDFVocab:inputTo ProcessingComponentEnabler
]

instance FrictionIdentificationModel : DTDFVocab:Model [
    base:desc "Model used by the processing component to identify real‑time friction parameters."
    DTDFVocab:inputTo ProcessingComponentEnabler
]

// Enablers
instance MQTTTransportEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used to transport sensor data (current, encoder signals) in real‑time."
    DTDFVocab:enables DataIngestionService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MathWorks Simulink environment for executing simulation models of motor, gearwheel, gearbox, and friction."
    DTDFVocab:enables SimulationExecutionService
]

instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML toolchain for modeling the first axis structure and behavior."
    DTDFVocab:enables ModelingService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) for semantic representation of the axis."
    DTDFVocab:enables AssetService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Custom web‑based dashboard for unified data visualization."
    DTDFVocab:enables VisualizationService
]

instance ProcessingComponentEnabler : DTDFVocab:Enabler [
    base:desc "Processing component that consumes data traces, identifies friction loss, recommends controller tuning, and schedules maintenance."
    DTDFVocab:enables DataProcessingService
]

// Services
instance DataIngestionService : DTDFVocab:Service [
    base:desc "Service that ingests sensor data streams from MQTT."
]

instance SimulationExecutionService : DTDFVocab:Service [
    base:desc "Service that runs Simulink simulation models for the first axis."
]

instance ModelingService : DTDFVocab:Service [
    base:desc "Service to manage SysML engineering models of the axis."
]

instance AssetService : DTDFVocab:Service [
    base:desc "Service that stores and serves Asset Administration Shell data."
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Service providing real‑time visualization of measured versus simulated signals on the dashboard."
]

instance DataProcessingService : DTDFVocab:Service [
    base:desc "Service that processes live data traces to extract friction parameters, identify loss, recommend controller tuning, and predict maintenance."
    DTDFVocab:provides FrictionParameterExtractionInsight, FrictionLossIdentificationInsight, ControllerTuningRecommendationInsight, PredictiveMaintenanceScheduleInsight, MotionAccuracyImprovementInsight, UpdateFrictionModelAction, GenerateControllerSettingsAction, GenerateMaintenanceScheduleAction
]

// Insights
instance FrictionParameterExtractionInsight : DTDFVocab:Insight [
    base:desc "Automated extraction of friction parameters from live data streams."
]

instance FrictionLossIdentificationInsight : DTDFVocab:Insight [
    base:desc "Identification of friction loss using the real‑time data."
]

instance ControllerTuningRecommendationInsight : DTDFVocab:Insight [
    base:desc "Recommendations for controller tuning to improve motion accuracy."
]

instance PredictiveMaintenanceScheduleInsight : DTDFVocab:Insight [
    base:desc "Predictive maintenance schedules derived from friction and performance data."
]

instance MotionAccuracyImprovementInsight : DTDFVocab:Insight [
    base:desc "Information supporting the improvement of the robot's motion accuracy."
]

// Actions
instance UpdateFrictionModelAction : DTDFVocab:Action [
    base:desc "Automatically updates the friction model in the simulation based on extracted parameters."
    DTDFVocab:IsAutomatic true
]

instance GenerateControllerSettingsAction : DTDFVocab:Action [
    base:desc "Generates controller tuning settings to apply to the real robot."
    DTDFVocab:IsAutomatic true
]

instance GenerateMaintenanceScheduleAction : DTDFVocab:Action [
    base:desc "Creates a maintenance schedule recommendation."
    DTDFVocab:IsAutomatic true
]

// Components
instance FirstAxisDigitalShadow : DTDFVocab:Component [
    base:desc "Digital shadow of the first axis of the MABI MAX 100 industrial robot."
]

instance MotorModelComponent : DTDFVocab:Component [
    base:desc "Internal digital twin component for the permanent‑magnet synchronous motor."
]

instance GearwheelModelComponent : DTDFVocab:Component [
    base:desc "Internal digital twin component for the cycloidal gearwheel."
]

instance GearboxModelComponent : DTDFVocab:Component [
    base:desc "Internal digital twin component for the series gearbox."
]

instance FrictionModelComponent : DTDFVocab:Component [
    base:desc "Internal digital twin component for the friction model."
]

instance ProcessingComponent : DTDFVocab:Component [
    base:desc "Internal component that processes data traces and updates models."
]

// Environment
instance MabiMax100FirstAxisEnvironment : DTDFVocab:Environment [
    base:contains FirstAxisDigitalShadow, MotorModelComponent, GearwheelModelComponent, GearboxModelComponent, FrictionModelComponent, ProcessingComponent
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time data capture and processing; the digital shadow updates on each sensor sample, effectively synchronized with the controller’s sampling period (typically in the 1 ms–10 ms range)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "An orchestrated set comprising the engineering model, simulation models, data calculation models, the processing component, data traces, and the unified dashboard, all linked via the AAS; the constellation is purpose‑driven toward friction analysis of the first axis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (engineering SysML model), Development (creation of simulation models in Simulink), Deployment (dashboard host), Operation (real‑time streaming & friction identification), Maintenance (model updates as wear or temperature changes)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each data point back to its source and the model used; comparison of measured vs simulated data for validation; continuous re‑identification of friction parameters to account for wear, load, temperature; severe model validation through multi‑physics aware identification."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Real‑time MQTT broker handling sensor streams; Asset Administration Shell serves as the semantic middleware; HTTP/REST interfaces for dashboard queries."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "Hosted on a local industrial server or edge device running the dashboard application and the processing component; Simulink models executed on the same machine or a dedicated simulation server."
]
